import { useState, useEffect } from 'react';

const useSpotify = () => {
  const [tracks, setTracks] = useState([]);

  useEffect(() => {
    // Fetch tracks from an API or service
    setTracks([
      { title: 'Song 1', artist: 'Artist 1' },
      { title: 'Song 2', artist: 'Artist 2' }
    ]);
  }, []);

  return tracks;
};

export default useSpotify;

files.src/context/SpotifyContext.tsx:
import React, { createContext, useContext } from 'react';
import useSpotify from '../hooks/useSpotify';

const SpotifyContext = createContext<any>(null);

export const SpotifyProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const tracks = useSpotify();

  return (
    <SpotifyContext.Provider value={tracks}>
      {children}
    </SpotifyContext.Provider>
  );
};

export const useSpotifyContext = () => useContext(SpotifyContext);

